import torch
from transformers import AutoModelForCausalLM

def load_state_dict(model_path: str) -> dict[str, torch.Tensor]:
    model = AutoModelForCausalLM.from_pretrained(
        model_path, torch_dtype=torch.float32
    )
    return {k: v.clone() for k, v in model.state_dict().items()}


def task_arithmetic_merge(
    base_path: str,
    finetuned_paths: list[str],
    lam: float = 0.5,
) -> AutoModelForCausalLM:
    base_sd = load_state_dict(base_path)

    # Compute and accumulate task vectors
    combined_tau: dict[str, torch.Tensor] = {}
    for ft_path in finetuned_paths:
        ft_sd = load_state_dict(ft_path)
        for k in base_sd:
            tau = ft_sd[k] - base_sd[k]
            combined_tau[k] = combined_tau.get(k, torch.zeros_like(tau)) + tau

    # Apply: θ_merged = θ_pre + λ * Σ τ_t
    merged_sd = {k: base_sd[k] + lam * combined_tau[k] for k in base_sd}

    base_model = AutoModelForCausalLM.from_pretrained(base_path)
    base_model.load_state_dict(merged_sd)
    return base_model


# Add coding + math capabilities to a base chat model
merged = task_arithmetic_merge(
    base_path="mistralai/Mistral-7B-v0.1",
    finetuned_paths=[
        "./mistral-7b-coder",
        "./mistral-7b-math",
    ],
    lam=0.5,
)
merged.save_pretrained("./task-arithmetic-merged")
